const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

interface Item {
  type: string;
}

interface QuoteStep {
  op: string;
  items?: Item[];
}

interface Scenario {
  steps: QuoteStep[];
}

export function processScenario(scenario: Scenario): unknown {
  const results = scenario.steps.map((step) => {
    const items = step.items ?? [];
    const policyBase = items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
    const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
    const premium = Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
    return { premium };
  });
  return { results };
}

