const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;

const MAIN_ITEM_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const COMPONENT_TYPES = new Set(["rune"]);

interface Item {
  type: string;
}

interface QuoteStep {
  op: string;
  items?: Item[];
}

interface Scenario {
  steps: QuoteStep[];
}

export function processScenario(scenario: Scenario): unknown {
  const results = scenario.steps.map((step) => {
    const items = step.items ?? [];
    const mainItemsBase = items
      .filter((item) => !COMPONENT_TYPES.has(item.type))
      .reduce((sum, item) => sum + (MAIN_ITEM_PREMIUMS[item.type] ?? 0), 0);
    const componentCounts = new Map<string, number>();
    for (const item of items) {
      if (COMPONENT_TYPES.has(item.type)) {
        componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
      }
    }
    let componentsBase = 0;
    for (const [, count] of componentCounts) {
      componentsBase += count === 3 ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
    }
    const policyBase = mainItemsBase + componentsBase;
    const premium = Math.ceil(policyBase + policyBase * FIRST_INSURANCE_RATE + PROCESSING_FEE);
    return { premium };
  });
  return { results };
}

