  type: string;
  cursed?: boolean;
  enchantment?: number;
}

interface Step {
  op: string;
  items?: Item[];
  item?: Item;
  damage?: number;
}

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: Step[];
}

